import re, pathlib
md = pathlib.Path('_response.md').read_text()
print("CHARS:", len(md))

# all 11 section headings
missing=[]
for n in range(1,12):
    if not re.search(rf'(?m)^## {n}\.', md):
        missing.append(n)
print("MISSING SECTIONS:", missing if missing else "none")

# mermaid blocks
blocks = re.findall(r'```mermaid(.*?)```', md, re.S)
print("MERMAID BLOCKS:", len(blocks))

# check breaking chars inside mermaid LABELS (edge labels |"..."| and node [..] / [(...)] / [[...]])
bad_chars = set('():;/"<>')
issues=[]
for i,b in enumerate(blocks,1):
    # edge labels between pipes
    for lbl in re.findall(r'\|"([^"]*)"\|', b):
        for c in '():;/<>':
            if c in lbl:
                issues.append((i,'edge',lbl,c))
    # node labels in [..] and [[..]] and [(..)]
    for lbl in re.findall(r'\[+\(?([^\[\]\(\)]*)\)?\]+', b):
        for c in ':;/"<>()':
            if c in lbl:
                issues.append((i,'node',lbl,c))
print("LABEL ISSUES:", issues if issues else "none")
